@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix ns1: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix ns2: <http://spdx.org/rdf/terms#> .
@prefix ns3: <https://cdif.org/0.1/> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a ns1:PhysicalDataSet,
                        ns1:StructuredDataSet,
                        schema1:DataDownload ;
                    schema1:contentUrl "https://example.org/data/gom-temp-cube-2025.nc" ;
                    schema1:encodingFormat "application/x-netcdf" ;
                    schema1:name "Gulf of Maine temperature cube (NetCDF-4)" ;
                    ns2:checksum [ a ns2:Checksum ;
                            ns2:algorithm "SHA256" ;
                            ns2:checksumValue "9f3c1a0b4e8d2f1e7a6c5b4d3a2918f0e1d2c3b4a5968778a9b0c1d2e3f40516" ] ;
                    ns3:fileSize 1.846e+02 ;
                    ns3:fileSizeUofM "MB" ;
                    ns3:hasPhysicalMapping [ ns1:isRequired true ;
                            ns1:locator "/lat" ;
                            ns3:format "decimal" ;
                            ns3:formats_InstanceVariable <https://example.org/var-lat> ;
                            ns3:physicalDataType "float32" ],
                        [ ns1:isRequired true ;
                            ns1:locator "/time" ;
                            ns3:format "days since 2024-01-01" ;
                            ns3:formats_InstanceVariable <https://example.org/var-time> ;
                            ns3:physicalDataType "int32" ],
                        [ ns1:isRequired true ;
                            ns1:locator "/temperature" ;
                            ns1:nullSequence "NaN" ;
                            ns3:format "decimal" ;
                            ns3:formats_InstanceVariable <https://example.org/var-temperature> ;
                            ns3:physicalDataType "float32" ],
                        [ ns1:isRequired true ;
                            ns1:locator "/lon" ;
                            ns3:format "decimal" ;
                            ns3:formats_InstanceVariable <https://example.org/var-lon> ;
                            ns3:physicalDataType "float32" ],
                        [ ns1:isRequired true ;
                            ns1:locator "/depth" ;
                            ns3:format "decimal" ;
                            ns3:formats_InstanceVariable <https://example.org/var-depth> ;
                            ns3:physicalDataType "float32" ] ] ;
            sh:resultMessage "Recommended: include dcterms:conformsTo to identify the standard or specification this distribution conforms to." ;
            sh:resultPath dcterms:conformsTo ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "Recommended: include dcterms:conformsTo to identify the standard or specification this distribution conforms to." ;
                    sh:minCount 1 ;
                    sh:path dcterms:conformsTo ;
                    sh:severity sh:Info ] ] .

